import{_ as e,c as t,o as a,a as o}from"./app.1e429f93.js";const y='{"title":"Validation State Values","description":"","frontmatter":{},"headers":[{"level":2,"title":"$invalid","slug":"invalid"},{"level":2,"title":"$dirty","slug":"dirty"},{"level":2,"title":"$anyDirty","slug":"anydirty"},{"level":2,"title":"$model","slug":"model"},{"level":2,"title":"$error","slug":"error"},{"level":2,"title":"$errors","slug":"errors"},{"level":2,"title":"$silentErrors","slug":"silenterrors"},{"level":2,"title":"$pending","slug":"pending"},{"level":2,"title":"$params","slug":"params"},{"level":2,"title":"$response","slug":"response"},{"level":2,"title":"$path","slug":"path"}],"relativePath":"api/state.md","lastUpdated":1777558301322}',i={},r=o('<h1 id="validation-state-values" tabindex="-1">Validation State Values <a class="header-anchor" href="#validation-state-values" aria-hidden="true">#</a></h1><p>There are two distinct structures present in <em>vuelidate</em>:</p><ul><li><code>validations</code> component option - the definition of your validation</li><li><code>v$ structure</code> - an object in the Vue VM, that holds the validation state</li></ul><p>The Validation state defines a set of properties which hold the output of user defined validation functions, following the provided <code>validations</code> property structure. The presence of those special reserved keywords means that you cannot specify your own validators with that name.</p><h2 id="invalid" tabindex="-1">$invalid <a class="header-anchor" href="#invalid" aria-hidden="true">#</a></h2><ul><li><p><strong>Type:</strong> <code>Boolean</code></p></li><li><p><strong>Details:</strong></p><p>Indicates the state of validation for given model becomes <code>true</code> when any of its child validators specified in options returns a <strong>falsy</strong> value.</p></li></ul><h2 id="dirty" tabindex="-1">$dirty <a class="header-anchor" href="#dirty" aria-hidden="true">#</a></h2><ul><li><p><strong>Type:</strong> <code>Boolean</code></p></li><li><p><strong>Details:</strong></p><p>A flag representing if the field under validation was touched by the user at least once. Usually it is used to decide if the message is supposed to be displayed to the end user. You can manage this flag manually by using <strong>$touch</strong> and <code>$reset</code> methods. It is set automatically when writing to <code>$model</code> value. The <code>$dirty</code> flag is considered true if given model was <code>$touched</code> or <strong>all of its children</strong> are <code>$dirty</code>.</p></li></ul><h2 id="anydirty" tabindex="-1">$anyDirty <a class="header-anchor" href="#anydirty" aria-hidden="true">#</a></h2><ul><li><p><strong>Type:</strong> <code>Boolean</code></p></li><li><p><strong>Details:</strong></p><p>A flag very similar to <code>$dirty</code>, with one exception. The <code>$anyDirty</code> flag is considered <code>true</code> if given model was <code>$touched</code> or <strong>any of its children</strong> are <code>$anyDirty</code> which means at least one descendant is <code>$dirty</code>.</p></li></ul><h2 id="model" tabindex="-1">$model <a class="header-anchor" href="#model" aria-hidden="true">#</a></h2><ul><li><p><strong>Type:</strong> <code>any</code></p></li><li><p><strong>Details:</strong></p><p>A reference to the original validated model. Reading this value will always give you exactly the same value as if you referenced the model directly. That means <code>this.v$.value.$model</code> is equivalent to <code>this.value</code> when read. Writing to that value will update the model and invoke <code>$touch</code> method automatically. This is very useful to use as <code>v-model</code> payload, providing a way of automatically marking given field as <code>$dirty</code> on first touch. Pairs well with <code>.lazy</code> modifier.</p></li></ul><h2 id="error" tabindex="-1">$error <a class="header-anchor" href="#error" aria-hidden="true">#</a></h2><ul><li><p><strong>Type:</strong> <code>Boolean</code></p></li><li><p><strong>Details:</strong></p><p>Convenience flag to easily decide if a message should be displayed. Equivalent to <code>this.$dirty &amp;&amp; !this.$pending &amp;&amp; this.$invalid</code>.</p></li></ul><h2 id="errors" tabindex="-1">$errors <a class="header-anchor" href="#errors" aria-hidden="true">#</a></h2><ul><li><p><strong>Type:</strong> <code>Array</code></p></li><li><p><strong>Details:</strong></p><p>Collection of all the error messages, collected for all child properties and nested forms (Vue components). Only contains errors from properties where <code>$dirty</code> equals <code>true</code>.</p></li></ul><h2 id="silenterrors" tabindex="-1">$silentErrors <a class="header-anchor" href="#silenterrors" aria-hidden="true">#</a></h2><ul><li><p><strong>Type:</strong> <code>Array</code></p></li><li><p><strong>Details:</strong></p><p>Collection of all the error messages, collected for all child properties and nested forms (Vue components).</p></li></ul><h2 id="pending" tabindex="-1">$pending <a class="header-anchor" href="#pending" aria-hidden="true">#</a></h2><ul><li><p><strong>Type:</strong> <code>Boolean</code></p></li><li><p><strong>Details:</strong></p><p>Indicates if any child async validator is currently pending. Always <code>false</code> if all validators are synchronous.</p></li></ul><h2 id="params" tabindex="-1">$params <a class="header-anchor" href="#params" aria-hidden="true">#</a></h2><ul><li><p><strong>Type:</strong> <code>Object</code></p></li><li><p><strong>Details:</strong></p><p>Contains types and parameters of all provided validators at the current level, as well as types and parameters of child validation groups, which may be declared using <code>withParams</code>. Useful as an input to your error rendering system. Safe to use in translated text.</p></li></ul><h2 id="response" tabindex="-1">$response <a class="header-anchor" href="#response" aria-hidden="true">#</a></h2><ul><li><p><strong>Type:</strong> <code>Boolean | Object | Null</code></p></li><li><p><strong>Default:</strong> <code>null</code></p></li><li><p><strong>Details:</strong></p><p>Contains the response and rejections of a validator.</p></li></ul><h2 id="path" tabindex="-1">$path <a class="header-anchor" href="#path" aria-hidden="true">#</a></h2><ul><li><p><strong>Type:</strong> <code>String</code></p></li><li><p><strong>Details:</strong></p><p>A dot notation nested path, of the current form leaf.</p></li></ul>',26),l=[r];function s(d,n,c,p,h,u){return a(),t("div",null,l)}var f=e(i,[["render",s]]);export{y as __pageData,f as default};
